import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface SleepData {
  lastNight: {
    duration: string;
    quality: string;
  };
  stagesBreakdown: {
    stage: string;
    percentage: number;
  }[];
  weeklyAverage: string;
}

export default function Widget() {
  const sleepData = response.data as SleepData;
  const { lastNight, stagesBreakdown } = sleepData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1F2937' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Last Night's Sleep
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#F8FAFC' }}>
              {lastNight.duration}
            </Typography>
            <Typography variant="body2" sx={{ color: '#10B981' }}>
              Quality: {lastNight.quality}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <PieChart
              series={[
                {
                  data: stagesBreakdown.map(stage => ({
                    id: stage.stage,
                    value: stage.percentage,
                  })),
                  color: ['#3B82F6', '#6366F1', '#F59E0B', '#EF4444'],
                },
              ]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            />
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Weekly Average
            </Typography>
            <Typography variant="h5" fontWeight={600} sx={{ color: '#F8FAFC' }}>
              {sleepData.weeklyAverage}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
